    public HealthcareServiceResponse SubmitLabResults(
        string patientId, string recordId, List<LabResult> labResults)
    {
        try
        {
            ValidateCallerIdentity();

            if (string.IsNullOrEmpty(patientId) || string.IsNullOrEmpty(recordId))
            {
