            if (labResults == null || labResults.Count == 0)
            {
                throw CreateFault("INVALID_INPUT",
                    "At least one lab result is required.", "");
            }

            lock (SyncLock)
            {
                if (!RecordStore.TryGetValue(recordId, out MedicalRecord record))
                {
                    throw CreateFault("RECORD_NOT_FOUND",
                        "Medical record not found.", recordId);
                }

                if (record.PatientId != patientId)
                {
                    throw CreateFault("PATIENT_MISMATCH",
                        "Patient ID does not match the record.", "");
                }

                if (record.LabResults == null)
                {
                    record.LabResults = new List<LabResult>();
                }

                record.LabResults.AddRange(labResults);
            }

            LogAudit("SubmitLabResults", "LabResult", recordId,
                $"Added {labResults.Count} lab result(s) for patient: {patientId}");

            return new HealthcareServiceResponse
