    private void ValidateCallerIdentity()
    {
        var context = ServiceSecurityContext.Current;
        if (context == null || context.IsAnonymous)
        {
            throw CreateFault("UNAUTHORIZED",
                "Caller identity could not be verified.",
                "No security context available.");
        }
    }

    private void ValidatePatient(Patient patient)
    {
        if (patient == null)
        {
            throw CreateFault("INVALID_INPUT",
                "Patient data is required.", "Patient is null.");
        }

        if (string.IsNullOrEmpty(patient.FirstName) ||
            string.IsNullOrEmpty(patient.LastName))
        {
            throw CreateFault("INVALID_INPUT",
                "Patient first name and last name are required.", "");
        }

        if (patient.DateOfBirth == default)
        {
            throw CreateFault("INVALID_INPUT",
                "Valid date of birth is required.", "");
        }
    }

    private void ValidateMedicalRecord(MedicalRecord record)
    {
        if (record == null)
        {
            throw CreateFault("INVALID_INPUT",
                "Medical record data is required.", "Record is null.");
        }

        if (string.IsNullOrEmpty(record.PatientId))
        {
            throw CreateFault("INVALID_INPUT",
                "Patient ID is required in the medical record.", "");
        }

        if (string.IsNullOrEmpty(record.ProviderId))
        {
            throw CreateFault("INVALID_INPUT",
                "Provider ID is required in the medical record.", "");
        }
    }

    private bool MatchesCriteria(Patient patient, PatientSearchCriteria criteria)
    {
        if (criteria == null) return true;

        if (!string.IsNullOrEmpty(criteria.PatientId) &&
            patient.PatientId != criteria.PatientId)
            return false;

        if (!string.IsNullOrEmpty(criteria.FirstName) &&
            !patient.FirstName.Equals(criteria.FirstName,
                StringComparison.OrdinalIgnoreCase))
            return false;

        if (!string.IsNullOrEmpty(criteria.LastName) &&
            !patient.LastName.Equals(criteria.LastName,
                StringComparison.OrdinalIgnoreCase))
            return false;

        if (criteria.DateOfBirth.HasValue &&
            patient.DateOfBirth.Date != criteria.DateOfBirth.Value.Date)
            return false;

        if (!string.IsNullOrEmpty(criteria.SocialSecurityNumber) &&
            patient.SocialSecurityNumber != criteria.SocialSecurityNumber)
            return false;

        return true;
    }

    private Patient ClonePatientSanitized(Patient patient)
    {
        return new Patient
        {
            PatientId = patient.PatientId,
            FirstName = patient.FirstName,
            LastName = patient.LastName,
            DateOfBirth = patient.DateOfBirth,
            SocialSecurityNumber = MaskSSN(patient.SocialSecurityNumber),
            Gender = patient.Gender,
            Address = patient.Address,
            PhoneNumber = patient.PhoneNumber,
            Email = patient.Email,
            InsuranceDetails = patient.InsuranceDetails
        };
    }

    private string MaskSSN(string ssn)
    {
        if (string.IsNullOrEmpty(ssn) || ssn.Length < 4)
            return "***-**-****";
        return "***-**-" + ssn.Substring(ssn.Length - 4);
    }

    private string GeneratePatientId()
    {
        return "PAT-" + Guid.NewGuid().ToString("N").Substring(0, 12).ToUpper();
    }

    private string GenerateRecordId()
    {
        return "REC-" + Guid.NewGuid().ToString("N").Substring(0, 12).ToUpper();
    }

    private void LogAudit(string action, string resourceType,
        string resourceId, string details)
    {
        var entry = new AuditEntry
        {
            AuditId = Guid.NewGuid().ToString(),
            Timestamp = DateTime.UtcNow,
            UserId = GetCurrentUserId(),
            Action = action,
            ResourceType = resourceType,
            ResourceId = resourceId,
            Details = details,
            SourceIP = GetClientIPAddress()
        };

        lock (SyncLock)
        {
            AuditLog.Add(entry);
        }

        Console.WriteLine(
            $"[AUDIT] {entry.Timestamp:O} | {entry.UserId} | " +
            $"{entry.Action} | {entry.ResourceType}:{entry.ResourceId} | " +
            $"{entry.Details}");
    }

    private string GetCurrentUserId()
    {
        try
        {
            var context = ServiceSecurityContext.Current;
            return context?.PrimaryIdentity?.Name ?? "UNKNOWN";
        }
        catch
        {
            return "UNKNOWN";
        }
    }

    private string GetClientIPAddress()
    {
        try
        {
            var context = OperationContext.Current;
            if (context?.IncomingMessageProperties != null &&
                context.IncomingMessageProperties.ContainsKey(
                    RemoteEndpointMessageProperty.Name))
            {
                var endpoint = context.IncomingMessageProperties[
                    RemoteEndpointMessageProperty.Name]
                    as RemoteEndpointMessageProperty;
                return endpoint?.Address ?? "UNKNOWN";
            }
        }
        catch { }
        return "UNKNOWN";
    }

    private FaultException<HealthcareFault> CreateFault(
        string errorCode, string errorMessage, string details)
    {
        var fault = new HealthcareFault
        {
            ErrorCode = errorCode,
            ErrorMessage = errorMessage,
            Details = details,
            Timestamp = DateTime.UtcNow
        };

        return new FaultException<HealthcareFault>(
            fault, new FaultReason(errorMessage));
    }
}

// ========== Custom Certificate Validator ==========

public class HealthcareCertificateValidator
    : System.IdentityModel.Selectors.X509CertificateValidator
{
    public override void Validate(X509Certificate2 certificate)
    {
        if (certificate == null)
        {
            throw new SecurityTokenValidationException(
                "Certificate is null.");
        }

        // Verify the certificate is not expired
        if (DateTime.Now > certificate.NotAfter ||
            DateTime.Now < certificate.NotBefore)
        {
            throw new SecurityTokenValidationException(
                "Certificate is expired or not yet valid.");
        }

        // Verify the certificate chain
        using (var chain = new X509Chain())
        {
            chain.ChainPolicy.RevocationMode = X509RevocationMode.Online;
            chain.ChainPolicy.RevocationFlag = X509RevocationFlag.EntireChain;
            chain.ChainPolicy.VerificationFlags =
                X509VerificationFlags.NoFlag;

            if (!chain.Build(certificate))
            {
                throw new SecurityTokenValidationException(
                    "Certificate chain validation failed.");
            }
        }

        // Additional checks: verify against allowed thumbprints
        var allowedThumbprints = new HashSet<string>(
            StringComparer.OrdinalIgnoreCase)
        {
            // Add allowed client certificate thumbprints here
            // "A1B2C3D4E5F6..."
        };

        // In production, uncomment and configure:
        // if (!allowedThumbprints.Contains(certificate.Thumbprint))
        // {
        //     throw new SecurityTokenValidationException(
        //         "Certificate is not in the allowed list.");
        // }

        Console.WriteLine(
            $"[SECURITY] Certificate validated: {certificate.Subject} " +
            $"(Thumbprint: {certificate.Thumbprint})");
    }
}

// ========== Binding Configuration Factory ==========

public static class HealthcareBindingFactory
{
    /// <summary>
    /// Creates a WS-Security binding with message-level encryption (AES-256)
    /// and mutual certificate authentication for HIPAA compliance.
    /// </summary>
    public static CustomBinding CreateSecureBinding()
    {
        // Asymmetric security binding element with mutual certificates
        var securityElement =
            SecurityBindingElement
                .CreateMutualCertificateBindingElement(
                    MessageSecurityVersion
                        .WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

        // Configure algorithm suite: AES-256 for encryption, SHA-256 for signing
        securityElement.DefaultAlgorithmSuite =
            SecurityAlgorithmSuite.Basic256Sha256;

        // Require signature confirmation
        securityElement.RequireSignatureConfirmation = true;

        // Enable derived keys for enhanced security
        securityElement.SetKeyDerivation(true);

        // Include timestamp for replay protection
        securityElement.IncludeTimestamp = true;
        securityElement.LocalClientSettings.MaxClockSkew =
            TimeSpan.FromMinutes(5);
        securityElement.LocalServiceSettings.MaxClockSkew =
            TimeSpan.FromMinutes(5);

        // Security header layout: Strict (WSS 1.1)
        securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;

        // Message protection order: sign then encrypt
        securityElement.MessageProtectionOrder =
            MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;

        // Text message encoding (SOAP 1.2)
        var textEncoding = new TextMessageEncodingBindingElement
        {
            MessageVersion = MessageVersion.Soap12WSAddressing10
        };
        textEncoding.ReaderQuotas.MaxStringContentLength = 1048576; // 1MB
        textEncoding.ReaderQuotas.MaxArrayLength = 1048576;
        textEncoding.ReaderQuotas.MaxDepth = 64;

        // HTTPS transport
        var httpsTransport = new HttpsTransportBindingElement
        {
            RequireClientCertificate = true,
            MaxReceivedMessageSize = 10485760, // 10MB
            MaxBufferSize = 10485760,
            TransferMode = TransferMode.Buffered
        };

        var customBinding = new CustomBinding(
            securityElement, textEncoding, httpsTransport);

        customBinding.ReceiveTimeout = TimeSpan.FromMinutes(10);
        customBinding.SendTimeout = TimeSpan.FromMinutes(10);

        return customBinding;
    }

    /// <summary>
    /// Creates a WSHttpBinding with message security for simpler configurations.
    /// </summary>
    public static WSHttpBinding CreateWSHttpSecureBinding()
    {
        var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
        {
            MaxReceivedMessageSize = 10485760,
            MaxBufferPoolSize = 10485760,
            ReaderQuotas =
            {
                MaxStringContentLength = 1048576,
                MaxArrayLength = 1048576,
                MaxDepth = 64
            },
            ReceiveTimeout = TimeSpan.FromMinutes(10),
            SendTimeout = TimeSpan.FromMinutes(10)
        };

        binding.Security.Message.ClientCredentialType =
            MessageCredentialType.Certificate;
        binding.Security.Message.AlgorithmSuite =
            SecurityAlgorithmSuite.Basic256Sha256;
        binding.Security.Message.EstablishSecurityContext = true;
        binding.Security.Message.NegotiateServiceCredential = false;

        binding.Security.Transport.ClientCredentialType =
            HttpClientCredentialType.Certificate;

        return binding;
    }
}

// ========== Service Host Configuration ==========

public class HealthcareServiceHostFactory
{
    private readonly string _baseAddress;
    private readonly string _serviceCertThumbprint;
    private readonly StoreLocation _certStoreLocation;

    public HealthcareServiceHostFactory(
        string baseAddress,
        string serviceCertThumbprint,
        StoreLocation certStoreLocation = StoreLocation.LocalMachine)
    {
        _baseAddress = baseAddress;
        _serviceCertThumbprint = serviceCertThumbprint;
        _certStoreLocation = certStoreLocation;
    }

    public ServiceHost CreateServiceHost()
    {
        var host = new ServiceHost(
            typeof(HealthcareRecordService),
            new Uri(_baseAddress));

        // Add the secure endpoint using custom binding
        var binding = HealthcareBindingFactory.CreateSecureBinding();

        var endpoint = host.AddServiceEndpoint(
            typeof(IHealthcareRecordService),
            binding,
            "secure");

        // Configure service credentials
        ConfigureServiceCredentials(host);

        // Configure service behaviors
        ConfigureServiceBehaviors(host);

        // Add metadata endpoint (for development; disable in production)
        ConfigureMetadata(host);

        return host;
    }

    private void ConfigureServiceCredentials(ServiceHost host)
    {
        // Service certificate for encryption and signing
        host.Credentials.ServiceCertificate.SetCertificate(
            _certStoreLocation,
            StoreName.My,
            X509FindType.FindByThumbprint,
            _serviceCertThumbprint);

        // Client certificate authentication settings
        host.Credentials.ClientCertificate.Authentication.CertificateValidationMode =
            X509CertificateValidationMode.Custom;
        host.Credentials.ClientCertificate.Authentication.CustomCertificateValidator =
            new HealthcareCertificateValidator();
        host.Credentials.ClientCertificate.Authentication.RevocationMode =
            X509RevocationMode.Online;

        // Peer trust for development (use ChainTrust in production)
        // host.Credentials.ClientCertificate.Authentication.CertificateValidationMode =
        //     X509CertificateValidationMode.ChainTrust;
    }

    private void ConfigureServiceBehaviors(ServiceHost host)
    {
        var behavior = host.Description.Behaviors
            .Find<ServiceDebugBehavior>();
        if (behavior == null)
        {
            behavior = new ServiceDebugBehavior();
            host.Description.Behaviors.Add(behavior);
        }
        // Disable detailed exception info in production
        behavior.IncludeExceptionDetailInFaults = false;

        var throttle = host.Description.Behaviors
            .Find<ServiceThrottlingBehavior>();
        if (throttle == null)
        {
            throttle = new ServiceThrottlingBehavior();
            host.Description.Behaviors.Add(throttle);
        }
        throttle.MaxConcurrentCalls = 100;
        throttle.MaxConcurrentInstances = 100;
        throttle.MaxConcurrentSessions = 100;
    }

    private void ConfigureMetadata(ServiceHost host)
    {
        var smb = host.Description.Behaviors
            .Find<ServiceMetadataBehavior>();
        if (smb == null)
        {
            smb = new ServiceMetadataBehavior();
            host.Description.Behaviors.Add(smb);
        }
        smb.HttpsGetEnabled = true;
        smb.HttpsGetUrl = new Uri(_baseAddress + "/mex");
    }
}

// ========== Client Proxy Factory ==========

public static class HealthcareClientFactory
{
    public static ChannelFactory<IHealthcareRecordService> CreateClientChannel(
        string endpointAddress,
        string clientCertThumbprint,
        string serviceCertThumbprint,
        StoreLocation storeLocation = StoreLocation.CurrentUser)
    {
        var binding = HealthcareBindingFactory.CreateSecureBinding();

        var endpointAddr = new EndpointAddress(
            new Uri(endpointAddress),
            EndpointIdentity.CreateX509CertificateIdentity(
                FindCertificate(serviceCertThumbprint, storeLocation)));

        var factory = new ChannelFactory<IHealthcareRecordService>(
            binding, endpointAddr);

        // Set client certificate
        factory.Credentials.ClientCertificate.SetCertificate(
            storeLocation,
            StoreName.My,
            X509FindType.FindByThumbprint,
            clientCertThumbprint);

        // Set service certificate for message encryption
        factory.Credentials.ServiceCertificate.SetDefaultCertificate(
            storeLocation,
            StoreName.TrustedPeople,
            X509FindType.FindByThumbprint,
            serviceCertThumbprint);

        factory.Credentials.ServiceCertificate.Authentication
            .CertificateValidationMode =
            X509CertificateValidationMode.PeerTrust;

        return factory;
    }

    private static X509Certificate2 FindCertificate(
        string thumbprint, StoreLocation storeLocation)
    {
        var store = new X509Store(StoreName.My, storeLocation);
        try
        {
            store.Open(OpenFlags.ReadOnly);
            var certs = store.Certificates.Find(
                X509FindType.FindByThumbprint, thumbprint, false);

            if (certs.Count == 0)
            {
                throw new InvalidOperationException(
                    $"Certificate with thumbprint '{thumbprint}' not found.");
            }

            return certs[0];
        }
        finally
        {
            store.Close();
        }
    }
}

