            {
                host.Opened += (s, e) =>
                    Console.WriteLine("[INFO] Service host opened.");
                host.Closed += (s, e) =>
                    Console.WriteLine("[INFO] Service host closed.");
                host.Faulted += (s, e) =>
                    Console.WriteLine("[ERROR] Service host faulted!");

                try
