                        Console.WriteLine($"  Endpoint: {ep.Address}");
                        Console.WriteLine($"  Binding:  {ep.Binding.Name}");
                        Console.WriteLine($"  Contract: {ep.Contract.Name}");
                        Console.WriteLine();
                    }

                    Console.WriteLine("Press [Enter] to stop the service...");
                    Console.ReadLine();

                    host.Close();
                }
                catch (CommunicationException ex)
                {
                    Console.WriteLine(
                        $"[ERROR] Communication exception: {ex.Message}");
                    Console.WriteLine();
                    Console.WriteLine("Note: Ensure the following:");
